sql:
SELECT course_name 
FROM courses 
ORDER BY course_name ASC;

external_knowledge:
- 'young navigators' refers to students; 
- 'set sail' is metaphorical for starting a course; 
- 'voyage' is a metaphor for the BSc Computer Science course; 
- 'charting their academic journey' refers to the details about the course’s location, duration, and study mode.

sql:
SELECT course_name, fees
FROM courses
WHERE fees > (SELECT AVG(fees) FROM courses);

SELECT COUNT(*)
FROM locations
WHERE location_id NOT IN (
    SELECT location_id
    FROM courses
);

SELECT course_name
FROM courses
WHERE CAST(SUBSTR(fees, 2) AS REAL) < (SELECT AVG(CAST(SUBSTR(fees, 2) AS REAL)) FROM courses);

SELECT AVG(fees) AS average_monthly_fees
FROM courses
WHERE location_id = 1;

SELECT option_code, start_date
FROM course_options
WHERE course_id = 1;

SELECT DISTINCT s.staff_name 
FROM staff s
JOIN staff_modules sm ON s.staff_id = sm.staff_id;
